1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	};
15	
16	const INSURANCE_VALUES: Record<string, number> = {
17	  sword: 1000,
18	  amulet: 600,
19	  staff: 800,
20	  potion: 400,
21	};
22	
23	const COMPONENT_INSURANCE_VALUE = 250;
24	const DEDUCTIBLE = 100;
25	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
26	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
27	
28	function isComponent(type: string): boolean {
29	  return !(type in MAIN_ITEM_PREMIUMS);
30	}
31	
32	function computeComponentPremium(items: any[]): number {
33	  const componentCounts: Record<string, number> = {};
34	
35	  for (const item of items) {
36	    if (isComponent(item.type)) {
37	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
38	    }
39	  }
40	
41	  let premium = 0;
42	  for (const count of Object.values(componentCounts)) {
43	    premium += count === COMPONENT_BLOCK_SIZE
44	      ? COMPONENT_BLOCK_PREMIUM
45	      : count * COMPONENT_PREMIUM;
46	  }
47	  return premium;
48	}
49	
50	function computeMainItemPremiums(items: any[]): { baseWithoutSurcharges: number; totalWithSurcharges: number } {
51	  let baseWithoutSurcharges = 0;
52	  let totalWithSurcharges = 0;
53	  for (const item of items) {
54	    if (!isComponent(item.type)) {
55	      const basePremium = MAIN_ITEM_PREMIUMS[item.type];
56	      baseWithoutSurcharges += basePremium;
57	      let itemPremium = basePremium;
58	      if (item.cursed) {
59	        itemPremium += basePremium * CURSED_SURCHARGE_RATE;
60	      }
61	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
62	        itemPremium += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
63	      }
64	      totalWithSurcharges += itemPremium;
65	    }
66	  }
67	  return { baseWithoutSurcharges, totalWithSurcharges };
68	}
69	
70	const FIRST_INSURANCE_RATE = 0.1;
71	const LOYALTY_DISCOUNT_RATE = 0.2;
72	const LOYALTY_THRESHOLD_YEARS = 2;
73	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
74	
75	function computeInsuranceSum(items: any[]): number {
76	  let sum = 0;
77	  for (const item of items) {
78	    if (isComponent(item.type)) {
79	      sum += COMPONENT_INSURANCE_VALUE;
80	    } else {
81	      sum += INSURANCE_VALUES[item.type];
82	    }
83	  }
84	  return sum;
85	}
86	
87	function processQuote(
88	  items: any[],
89	  customer: any,
90	  quoteCount: number,
91	  stepIndex: number,
92	  policies: Map<number, { items: any[]; remainingCap: number }>,
93	): { premium: number } {
94	  const componentPremium = computeComponentPremium(items);
95	  const mainItems = computeMainItemPremiums(items);
96	  const totalItemPremium = mainItems.totalWithSurcharges + componentPremium;
97	  const policyBase = mainItems.baseWithoutSurcharges + componentPremium;
98	
99	  let policyModifiers = policyBase * FIRST_INSURANCE_RATE;
100	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
101	    policyModifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
102	  }
103	  if (quoteCount > 1) {
104	    policyModifiers -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
105	  }
106	
107	  const premium = Math.ceil(totalItemPremium + policyModifiers + PROCESSING_FEE);
108	  const insuranceSum = computeInsuranceSum(items);
109	  policies.set(stepIndex, { items, remainingCap: insuranceSum * 2 });
110	
111	  return { premium };
112	}
113	
114	function processClaim(
115	  step: any,
116	  policies: Map<number, { items: any[]; remainingCap: number }>,
117	): { payout: number; remainingCap: number } {
118	  const policy = policies.get(step.policy)!;
119	
120	  let totalPayout = 0;
121	  for (const damage of step.incident.damages) {
122	    let damageAmount = damage.amount;
123	    const item = policy.items.find((i: any) => i.type === damage.itemType);
124	    if (item && item.enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD) {
125	      damageAmount *= CLAIM_HIGH_ENCHANTMENT_RATE;
126	    }
127	    const payout = damageAmount - DEDUCTIBLE;
128	    totalPayout += Math.max(0, payout);
129	  }
130	
131	  totalPayout = Math.min(totalPayout, policy.remainingCap);
132	  policy.remainingCap -= totalPayout;
133	
134	  return { payout: Math.floor(totalPayout), remainingCap: policy.remainingCap };
135	}
136	
137	export function processScenario(scenario: any): any {
138	  const results: any[] = [];
139	  let quoteCount = 0;
140	  const policies: Map<number, { items: any[]; remainingCap: number }> = new Map();
141	
142	  for (let i = 0; i < scenario.steps.length; i++) {
143	    const step = scenario.steps[i];
144	    if (step.op === "quote") {
145	      quoteCount++;
146	      results.push(processQuote(step.items, scenario.customer, quoteCount, i, policies));
147	    } else if (step.op === "claim") {
148	      results.push(processClaim(step, policies));
149	    }
150	  }
151	
152	  return { results };
153	}
