23	}
24	
25	function computeComponentPremium(items: any[]): number {
26	  const componentCounts: Record<string, number> = {};
27	
28	  for (const item of items) {
29	    if (isComponent(item.type)) {
30	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
31	    }
32	  }
33	
34	  let premium = 0;
35	  for (const count of Object.values(componentCounts)) {
36	    premium += count === COMPONENT_BLOCK_SIZE
37	      ? COMPONENT_BLOCK_PREMIUM
38	      : count * COMPONENT_PREMIUM;
39	  }
40	  return premium;
41	}
42	
43	function computeMainItemPremiums(items: any[]): { baseWithoutSurcharges: number; totalWithSurcharges: number } {
44	  let baseWithoutSurcharges = 0;
45	  let totalWithSurcharges = 0;
46	  for (const item of items) {
47	    if (!isComponent(item.type)) {
48	      const basePremium = MAIN_ITEMS[item.type].premium;
49	      baseWithoutSurcharges += basePremium;
50	      let itemPremium = basePremium;
51	      if (item.cursed) {
52	        itemPremium += basePremium * CURSED_SURCHARGE_RATE;
53	      }
54	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
55	        itemPremium += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
56	      }
57	      totalWithSurcharges += itemPremium;
58	    }
59	  }
60	  return { baseWithoutSurcharges, totalWithSurcharges };
61	}
62	
63	const FIRST_INSURANCE_RATE = 0.1;
64	const LOYALTY_DISCOUNT_RATE = 0.2;
65	const LOYALTY_THRESHOLD_YEARS = 2;
66	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
67	
68	function computeInsuranceSum(items: any[]): number {
69	  let sum = 0;
70	  for (const item of items) {
71	    if (isComponent(item.type)) {
72	      sum += COMPONENT_INSURANCE_VALUE;
73	    } else {
74	      sum += MAIN_ITEMS[item.type].insuranceValue;
75	    }
76	  }
77	  return sum;
78	}
79	
80	function processQuote(
81	  items: any[],
82	  customer: any,
83	  quoteCount: number,
84	  stepIndex: number,
85	  policies: Map<number, { items: any[]; remainingCap: number }>,
86	): { premium: number } {
87	  const componentPremium = computeComponentPremium(items);
88	  const mainItems = computeMainItemPremiums(items);
89	  const totalItemPremium = mainItems.totalWithSurcharges + componentPremium;
90	  const policyBase = mainItems.baseWithoutSurcharges + componentPremium;
91	
92	  let policyModifiers = policyBase * FIRST_INSURANCE_RATE;
93	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
94	    policyModifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
95	  }
96	  if (quoteCount > 1) {
97	    policyModifiers -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
98	  }
99	
100	  const premium = Math.ceil(totalItemPremium + policyModifiers + PROCESSING_FEE);
101	  const insuranceSum = computeInsuranceSum(items);
102	  policies.set(stepIndex, { items, remainingCap: insuranceSum * 2 });
103	
104	  return { premium };
105	}
106	
107	function processClaim(
108	  step: any,
109	  policies: Map<number, { items: any[]; remainingCap: number }>,
110	): { payout: number; remainingCap: number } {
111	  const policy = policies.get(step.policy)!;
112	
113	  let totalPayout = 0;
114	  for (const damage of step.incident.damages) {
115	    let damageAmount = damage.amount;
116	    const item = policy.items.find((i: any) => i.type === damage.itemType);
117	    if (item && item.enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD) {
118	      damageAmount *= CLAIM_HIGH_ENCHANTMENT_RATE;
119	    }
120	    const payout = damageAmount - DEDUCTIBLE;
121	    totalPayout += Math.max(0, payout);
122	  }
123	
124	  totalPayout = Math.min(totalPayout, policy.remainingCap);
125	  policy.remainingCap -= totalPayout;
126	
127	  return { payout: Math.floor(totalPayout), remainingCap: policy.remainingCap };
128	}
129	
130	export function processScenario(scenario: any): any {
131	  const results: any[] = [];
132	  let quoteCount = 0;
133	  const policies: Map<number, { items: any[]; remainingCap: number }> = new Map();
134	
135	  for (let i = 0; i < scenario.steps.length; i++) {
136	    const step = scenario.steps[i];
137	    if (step.op === "quote") {
138	      quoteCount++;
139	      results.push(processQuote(step.items, scenario.customer, quoteCount, i, policies));
140	    } else if (step.op === "claim") {
141	      results.push(processClaim(step, policies));
142	    }
143	  }
144	
145	  return { results };
146	}
